def GetWin(string):
    if re.search(r"1{4,}|1(?:.{7}1){3,}|1(?:.{8}1){3,}|1(?:.{6}1){3,}",string):
        return "Red"
    if re.search(r"2{4,}|2(?:.{7}2){3,}|2(?:.{8}2){3,}|2(?:.{6}2){3,}",string):
        return "Yellow"
    return "Draw"

def who_is_winner(moves):
    G = {(c, r):' ' for r in range(6) for c in range(7)}

    for col, colour in [(ord(m[0]) - ord('A'), m[2]) for m in moves]:
        for row in range(6):
            if G[(col, row)] == ' ':
                G[(col,row)] = colour
                break
        if colour*4 in ' '.join([''.join(G[(col, k)] for k in range(6)),
                                 ''.join(G[(k, row)] for k in range(7)),
                                 ''.join(G.get((k, row - col + k), ' ') for k in range(7)),
                                 ''.join(G.get((k, row + col - k), ' ') for k in range(7))]): return {'Y':'Yellow', 'R':'Red'}[colour]
    return 'Draw'

import string


def vertical_win(game_board_matrix):
    win = 0
    for x_value in range(0, 7):
        coloumn = [game_board_matrix[i][x_value] for i in range(0, 6)]
        i=0
        while i < 3:
            row4 = coloumn [i:i+4]
            i+=1
            if row4.count('R') == 4:
                win = 1
            if row4.count('Y') == 4:
                win = 1
    if win == 1:
