def getSum(dp, pos, s, e, type_):
    if e < s:
        return 0

    if type_=='D':
        if e==m-1:
            return dp[pos][s]
        return dp[pos][s]-dp[pos][e+1]
    else:
        if e==n-1:
            return dp[s][pos]
        return dp[s][pos]-dp[e+1][pos]

