from collections import defaultdict

def find_website_groups(queries):
    hostname_to_queries = defaultdict(list)

    for query in queries:
        hostname = query.split('/')[2].split('.')[0]
        hostname_to_queries[hostname].append(query)

    website_groups = []
    for hostname, queries in hostname_to_queries.items():
        if len(queries) > 1:
            website_groups.append(hostname)

    return len(website_groups), ' '.join(website_groups)

