def kruskal_mst(V: int, E: int, edges: List[List[int]]) -> List[List[int]]:
    # Sort edges by weight
    edges.sort(key=lambda x: x[2])

    parent = list(range(V))
    rank = [0] * V

    def find(x):
        if parent[x] != x:
            parent[x] = find(parent[x])
        return parent[x]

    def union(x, y):
        root_x = find(x)
        root_y = find(y)
        if root_x == root_y:
            return
        if rank[root_x] < rank[root_y]:
            parent[root_x] = root_y
        elif rank[root_x] > rank[root_y]:
            parent[root_y] = root_x
        else:
            parent[root_y] = root_x
            rank[root_x] += 1

    mst = []
    for u, v, w in edges:
        if find(u) != find(v):
            mst.append([u, v])
            union(u, v)

    return mst

