def count_paths(n, m, labyrinth):
    MOD = 10**9 + 7

    # Initialize the DP table
    dp = [[0] * (m + 1) for _ in range(n + 1)]
    dp[1][1] = 1  # Starting point

    # Directions: right and down
    directions = [(0, 1), (1, 0)]

    # Fill the DP table
    for i in range(1, n + 1):
        for j in range(1, m + 1):
            if labyrinth[i-1][j-1] == 'R':
                continue
            for dx, dy in directions:
                x, y = i + dx, j + dy
                if 1 <= x <= n and 1 <= y <= m and labyrinth[x-1][y-1] != 'R':
                    dp[i][j] = (dp[i][j] + dp[x][y]) % MOD

    return dp[n][m]

