def count_paths(n, m, labyrinth):
    MOD = 10**9 + 7

    # Initialize the DP table with zeros
    dp = [[0 for _ in range(m)] for _ in range(n)]

    # Starting point
    dp[0][0] = 1

    # Fill the DP table
    for i in range(n):
        for j in range(m):
            if labyrinth[i][j] == 'R':
                continue

            if i > 0:
                dp[i][j] += dp[i-1][j]
                dp[i][j] %= MOD

            if j > 0:
                dp[i][j] += dp[i][j-1]
                dp[i][j] %= MOD

