from functools import lru_cache

@lru_cache(None)
def count_paths(n, m, x, y, obstacles):
    if x == n or y == m or (x, y) in obstacles:
        return 0
    if x == n - 1 and y == m - 1:
        return 1

    right_paths = count_paths(n, m, x + 1, y, obstacles)
    down_paths = count_paths(n, m, x, y + 1, obstacles)

    return (right_paths + down_paths) % (10**9 + 7)

