def count_paths(n: int, m: int, labyrinth: List[str]) -> int:
    MOD = 10**9 + 7

    # Initialize the DP table
    dp = [[0] * (m + 1) for _ in range(n + 1)]
    dp[1][1] = 1  # Starting point

    # Fill the DP table
    for i in range(1, n + 1):
        for j in range(1, m + 1):
            if labyrinth[i-1][j-1] == 'R':
                continue
            if i > 1:
                dp[i][j] += dp[i-1][j]
                dp[i][j] %= MOD
            if j > 1:
                dp[i][j] += dp[i][j-1]
                dp[i][j] %= MOD

    return dp[n][m]

