def max_pair_sum(nums1: List[int], nums2: List[int]) -> int:
    # Ensure both lists are non-empty
    if not nums1 or not nums2:
        raise ValueError("Both lists must be non-empty")

    # Initialize variables to store the maximum sum and the corresponding indices
    max_sum = float('-inf')
    max_indices = (0, 0)

    # Iterate through both lists to find the maximum sum of pairs
    for i in range(len(nums1)):
