def count_paths(n: int, m: int, labyrinth: List[List[str]]) -> int:
    MOD = 10**9 + 7

    # Initialize a DP table where dp[i][j] represents the number of ways to reach (i, j)
    dp = [[0] * m for _ in range(n)]

    # Starting point
    dp[0][0] = 1

    # Fill the DP table
    for i in range(n):
        for j in range(m):
            if labyrinth[i][j] == '.':
                if i > 0:
                    dp[i][j] += dp[i-1][j]
                if j > 0:
                    dp[i][j] += dp[i][j-1]
                dp[i][j] %= MOD

    return dp[n-1][m-1]

