def min_spanning_tree_with_edge_costs(graph: List[List[int]]) -> List[int]:
    # Initialize data structures
    n = len(graph)
    parent = [-1] * n
    rank = [0] * n
    edges = []

    # Build a list of edges with their costs
    for i in range(n):
        for j in range(i + 1, n):
            edges.append((i, j, graph[i][j]))

    # Sort edges by cost
    edges.sort(key=lambda x: x[2])

    # Function to find the parent of a node
    def find(x):
        if parent[x] == -1:
            return x
        return find(parent[x])

    # Function to union two sets
    def union(x, y):
        root_x = find(x)
        root_y = find(y)
        if root_x != root_y:
            if rank[root_x] < rank[root_y]:
                parent[root_x] = root_y
            elif rank[root_x] > rank[root_y]:
                parent[root_y] = root_x
            else:
                parent[root_y] = root_x
                rank[root_x] += 1

    # Main algorithm to find the minimum spanning tree
    mst = []
    for u, v, w in edges:
        if find(u) != find(v):
            union(u, v)
            mst.append((u, v, w))

    # Return the indices of the edges in the resulting spanning tree
    return [i for i, (u, v, w) in enumerate(mst)]

