def kruskal_mst(graph):
    # Initialize disjoint set data structure
    parent = {node: node for node in graph}
    rank = {node: 0 for node in graph}

    # Function to find the root of a node
    def find(node):
        if parent[node] != node:
            parent[node] = find(parent[node])
        return parent[node]

    # Function to union two nodes
    def union(node1, node2):
        root1 = find(node1)
        root2 = find(node2)
        if root1 == root2:
            return
        if rank[root1] < rank[root2]:
            parent[root1] = root2
        elif rank[root1] > rank[root2]:
            parent[root2] = root1
        else:
            parent[root2] = root1
            rank[root1] += 1

    # Sort edges by weight
    edges = sorted(graph.items(), key=lambda x: x[1])

    mst = []
    total_weight = 0

    for u, v, w in edges:
        if w <= 1000 and w >= -1000 and (w % 2 != 0 or w % 3 != 0):
            if find(u) != find(v):
                union(u, v)
                mst.append((u, v, w))
                total_weight += w

    return mst, total_weight

