def max_subarray_without_repeating_consecutive(nums: List[int]) -> int:
    if not nums:
        return 0

    n = len(nums)
    dp = [0] * n
    dp[0] = nums[0]

    for i in range(1, n):
        # Check if the current element can be added to the previous subarray without repeating consecutive elements
        if i > 1 and nums[i] != nums[i-1] and nums[i] != nums[i-2]:
            dp[i] = dp[i-1] + nums[i]
        else:
            dp[i] = nums[i]

    return max(dp)

def max_non_consecutive_subarray_sum(arr):
    if not arr:
        return 0

    n = len(arr)
    dp = [0] * n

    dp[0] = arr[0]

    for i in range(1, n):
        dp[i] = max(dp[i-1], dp[i-2] + arr[i])

    return dp[-1]

