def remove_duplicates(nums):
    if not nums:
        return []

    # Initialize pointers for the result list and the current index
    result_index = 0
    current_count = 1

    # Iterate through the array starting from the second element
    for i in range(1, len(nums)):
        if nums[i] == nums[i-1]:
            current_count += 1
        else:
            # If the current count is less than or equal to 2, append the element to the result list
            if current_count <= 2:
                nums[result_index] = nums[i]
                result_index += 1
            current_count = 1

    # Append any remaining elements that are less than or equal to 2 to the result list
    if current_count <= 2:
        nums[result_index] = nums[-1]
        result_index += 1

    return nums[:result_index]

